  ('heelevel3-c5fb3965-moex-00160', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-110-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'single_choice', '下列何者非屬對外發生法律效果之規定？', '["公民與政治權利國際公約及經濟社會文化權利國際公約施行法", "大學法施行細則", "地方稅法通則", "中央政府年度總預算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00161', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-110-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'single_choice', '依司法院大法官解釋，關於剝奪人身自由應遵守之正當法律程序，下列何者正確？', '["非法入境之大陸地區人民，不受人身自由之正當法律程序保障", "傳染病病人之強制隔離決定，應由法院為之", "行政執行之管收決定，得由法院書面審理為之", "外國人之暫時收容決定，得先由行政機關為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL),
  ('heelevel3-c5fb3965-moex-00162', 'heelevel3-c5fb3965', 'heelevel3-c5fb3965-moex-110-3082b5f1', 'sub-heelevel3-c5fb3965-03', NULL, 'single_choice', '當人民提起課予義務訴訟，而行政法院認為行政機關之不作為雖屬違法，但就人民所請求之行政 處分的作成行政機關尚有裁量空間時，應如何裁判？', '["以判決命行政機關作成原告所申請內容之行政處分", "以原告之訴無理由，判決駁回", "以判決命行政機關遵照判決之法律見解對於原告作成處分", "以原告之訴不合法，裁定駁回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "戶政"}'::jsonb, NULL)
